11	  const [framing, setFraming] = useState<Framing>(INITIAL_FRAMING);
12	  const [seen, setSeen] = useState<ReadonlySet<Framing>>(
13	    () => new Set<Framing>([INITIAL_FRAMING])
14	  );
15	  const [flashKey, setFlashKey] = useState(0);
16	
17	  const handleToggle = useCallback(() => {
18	    const next = swapFraming(framing);
19	    setFraming(next);
20	    setFlashKey((n) => n + 1);
21	    setSeen((prev) => {
22	      if (prev.has(next)) {
23	        return prev;
24	      }
25	      const updated = new Set(prev);
26	      updated.add(next);
27	      return updated;
28	    });
29	  }, [framing]);
30	
31	  const showEmptyMirrorLine = seen.size === 2;
32	
33	  return (
34	    <div className="space-y-4">
35	      <Prompt framing={framing} onToggle={handleToggle} />
36	      <Response flashKey={flashKey} framing={framing} />
37	      {showEmptyMirrorLine && (
38	        <p className="fade-in animate-in pl-1 text-foreground/55 text-sm italic leading-6 duration-300">
39	          It agreed with both. That&apos;s all its agreement was ever going to
