"use client";

import { Button } from "@repo/design-system/components/ui/button";
import { useCallback, useState } from "react";
import { Expandable } from "../../components/expandable";
import { MetaAside } from "../../components/meta-aside";
import { CleanupJob } from "./cleanup-job";
import { IncidentEssay } from "./incident-essay";
import { Nudges } from "./nudges";
import { Pipeline } from "./pipeline";
import type { Stage } from "./stage";

const REVEAL_LINE =
  "The validation never told the truth about this field. It just always said yes.";

export function Proof() {
  const [stage, setStage] = useState<Stage>("initial");

  const send = useCallback(() => setStage("sent"), []);
  const advance = useCallback(() => setStage("aged"), []);
  const reveal = useCallback(() => setStage("revealed"), []);
  const reset = useCallback(() => setStage("initial"), []);

  return (
    <div className="space-y-6">
      <Nudges stage={stage} />
      <Pipeline stage={stage} />

      <div className="flex flex-wrap items-center gap-3">
        {stage === "initial" && (
          <Button onClick={send} type="button">
            Send renewal
          </Button>
        )}
        {stage === "sent" && (
          <Button onClick={advance} type="button">
            Advance 12 months
          </Button>
        )}
        {stage === "aged" && (
          <Button onClick={reveal} type="button">
            See what the validation did
          </Button>
        )}
        {stage !== "initial" && (
          <Button onClick={reset} type="button" variant="ghost">
            Reset
          </Button>
        )}
      </div>

      <CleanupJob stage={stage} />

      {stage === "revealed" && (
        <div className="fade-in animate-in space-y-3 rounded-2xl border border-border bg-card/40 p-5 duration-300 sm:p-6">
          <p className="font-medium font-mono text-[0.65rem] text-ht-cyan-700 uppercase tracking-[0.2em] dark:text-ht-cyan-300/90">
            What just happened
          </p>
          <p className="text-foreground/85 leading-7">
            <code className="font-mono text-sm">z.coerce.date()</code> on{" "}
            <code className="font-mono text-sm">undefined</code> returns{" "}
            <code className="font-mono text-sm">new Date(0)</code> — January 1,
            1970. The schema didn&apos;t validate. It manufactured.
          </p>
          <p className="text-foreground/70 italic leading-7">{REVEAL_LINE}</p>
          <p className="text-foreground/70 leading-7">
            The check was working. It was working on a problem that no longer
            existed.
          </p>
        </div>
      )}

      <MetaAside className="mt-8 max-w-prose" variant="block">
        A check that can transform input into compliance isn&apos;t a check.
        It&apos;s a translator.
      </MetaAside>

      <Expandable label="Did you know? The day the records vanished.">
        <IncidentEssay />
      </Expandable>
    </div>
  );
}

